use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::PathBuf;

use distributed_inference::acoustic::AcousticEngine;
use hound::WavReader;

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let mut audio_path: Option<PathBuf> = None;
    let mut out_path = PathBuf::from("/tmp/acoustic.ply");

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--audio" => {
                i += 1;
                audio_path = Some(PathBuf::from(&args[i]));
            }
            "--out" => {
                i += 1;
                out_path = PathBuf::from(&args[i]);
            }
            other => panic!("unknown arg {}", other),
        }
        i += 1;
    }

    let audio_path = audio_path.expect("--audio <wav> required");
    eprintln!("[acoustic] loading audio {:?}", audio_path);

    let mut reader = WavReader::open(audio_path).unwrap();
    let spec = reader.spec();
    // read samples to f32
    let samples: Vec<f32> = match spec.sample_format {
        hound::SampleFormat::Int => reader
            .samples::<i16>()
            .map(|s| s.unwrap() as f32 / 32768.0)
            .collect(),
        hound::SampleFormat::Float => reader.samples::<f32>().map(|s| s.unwrap()).collect(),
    };

    eprintln!("[acoustic] decoded {} samples", samples.len());

    let mut engine = AcousticEngine::new();

    // Process in chunks of 1024
    let chunk_size = 1024;
    let mut verts: Vec<[f32; 3]> = Vec::new();
    let mut cols: Vec<[u8; 3]> = Vec::new();

    for (i, chunk) in samples.chunks(chunk_size).enumerate() {
        if chunk.len() < chunk_size {
            break;
        }

        let result = engine.siphon_audio(chunk, format!("chunk_{}", i));

        // map time, frequency (simulated by trace), amplitude to x, y, z
        // map entropy to color
        let time = i as f32;
        let trace = result.vector.boundary_trace as f32 / 1000.0;
        let amplitude = result
            .vector
            .bulk_state
            .iter()
            .cloned()
            .fold(0f32, f32::max);

        verts.push([time, trace, amplitude]);

        // color based on entropy
        let entropy_color = (result.entropy.min(1.0) * 255.0) as u8;
        cols.push([entropy_color, 255 - entropy_color, 128]);
    }

    // Write PLY
    eprintln!("[acoustic] saving {} points to {:?}", verts.len(), out_path);
    let mut file = BufWriter::new(File::create(&out_path).unwrap());
    writeln!(file, "ply").unwrap();
    writeln!(file, "format ascii 1.0").unwrap();
    writeln!(file, "element vertex {}", verts.len()).unwrap();
    writeln!(file, "property float x").unwrap();
    writeln!(file, "property float y").unwrap();
    writeln!(file, "property float z").unwrap();
    writeln!(file, "property uchar red").unwrap();
    writeln!(file, "property uchar green").unwrap();
    writeln!(file, "property uchar blue").unwrap();
    writeln!(file, "end_header").unwrap();

    for (v, c) in verts.iter().zip(cols.iter()) {
        writeln!(
            file,
            "{} {} {} {} {} {}",
            v[0], v[1], v[2], c[0], c[1], c[2]
        )
        .unwrap();
    }

    eprintln!("[acoustic] done");
}
